const breakdown = $('Get Yesterday\'s New Listings').all().map(i => i.json);
const topListings = $('Get Top New Listings').all().map(i => i.json);

// Group by province
const byProvince = {};
breakdown.forEach(row => {
  if (!byProvince[row.province]) {
    byProvince[row.province] = { province: row.province, types: [], total: 0 };
  }
  byProvince[row.province].types.push(row);
  byProvince[row.province].total += Number(row.count);
});

const totalNew = breakdown.reduce((s, r) => s + Number(r.count), 0);
const today = new Date().toLocaleDateString('en-ZA', { weekday: 'long', day: 'numeric', month: 'long' });

if (totalNew === 0) {
  return [{ json: { message: `No new listings added yesterday (${today}).`, total: 0, blocks: '[]' } }];
}

const blocks = [
  {
    type: 'header',
    text: { type: 'plain_text', text: `Daily Property Update - ${today}` }
  },
  {
    type: 'section',
    fields: [
      { type: 'mrkdwn', text: `*Total New Listings*\n${totalNew}` },
      { type: 'mrkdwn', text: `*Provinces Active*\n${Object.keys(byProvince).length}` }
    ]
  },
  { type: 'divider' }
];

// Add province sections
Object.values(byProvince)
  .sort((a, b) => b.total - a.total)
  .forEach(prov => {
    const typesSummary = prov.types
      .map(t => `${t.property_type}: ${t.count} (avg R${Number(t.avg_price).toLocaleString()})`)
      .join(' | ');
    blocks.push({
      type: 'section',
      text: {
        type: 'mrkdwn',
        text: `*${prov.province}* - ${prov.total} new listings\n${typesSummary}`
      }
    });
  });

blocks.push({ type: 'divider' });
blocks.push({
  type: 'section',
  text: { type: 'mrkdwn', text: '*Top 5 New Listings*' }
});

topListings.slice(0, 5).forEach(listing => {
  blocks.push({
    type: 'section',
    text: {
      type: 'mrkdwn',
      text: `• <${listing.url}|${listing.title}>\n  R${Number(listing.price).toLocaleString()} | ${listing.bedrooms}bed/${listing.bathrooms}bath | ${listing.city}, ${listing.province}`
    }
  });
});

blocks.push({
  type: 'actions',
  elements: [
    {
      type: 'button',
      text: { type: 'plain_text', text: 'View All Listings' },
      url: 'https://puraestate.co.za/properties',
      style: 'primary'
    }
  ]
});

return [{
  json: {
    total_new: totalNew,
    provinces: Object.keys(byProvince).length,
    blocks: JSON.stringify(blocks),
    report_date: today
  }
}];

// Define province-specific Slack channels
const channelMap = {
  'Western Cape': '#wc-listings',
  'Gauteng': '#gp-listings',
  'KwaZulu-Natal': '#kzn-listings',
  'Eastern Cape': '#ec-listings',
  'Limpopo': '#lp-listings',
  'Mpumalanga': '#mp-listings',
  'North West': '#nw-listings',
  'Northern Cape': '#nc-listings',
  'Free State': '#fs-listings'
};

const breakdown = $('Get Yesterday\'s New Listings').all().map(i => i.json);

// Group by province
const byProvince = {};
breakdown.forEach(row => {
  const prov = row.province;
  if (!byProvince[prov]) byProvince[prov] = [];
  byProvince[prov].push(row);
});

const results = [];

Object.entries(byProvince).forEach(([province, rows]) => {
  const channel = channelMap[province];
  if (!channel) return;

  const total = rows.reduce((s, r) => s + Number(r.count), 0);
  const summary = rows.map(r => `• ${r.property_type}: ${r.count} listings | Avg R${Number(r.avg_price).toLocaleString()}`).join('\n');

  results.push({
    json: {
      channel,
      province,
      total,
      message: `*${province} Daily Update*\n${total} new listings added yesterday\n\n${summary}\n\n<https://puraestate.co.za/properties?province=${encodeURIComponent(province)}|Browse ${province} Properties>`
    }
  });
});

return results;
